const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.QUEUE_NAME || 'payment_events';
const PREFETCH = Number(process.env.PREFETCH || 10);

function toInt(v, fallback = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? Math.trunc(n) : fallback;
}

function normalizeCurrency(cur) {
  const c = String(cur || '').trim().toUpperCase();
  return c || 'USD';
}

function parseJSON(content) {
  if (Buffer.isBuffer(content)) content = content.toString('utf8');
  if (typeof content !== 'string') return content;
  return JSON.parse(content);
}

function validateEvent(event) {
  if (!event || typeof event !== 'object') throw new Error('Invalid event');
  if (!event.type || typeof event.type !== 'string') throw new Error('Missing type');
  if (!event.paymentId || typeof event.paymentId !== 'string') throw new Error('Missing paymentId');
  return event;
}

async function chargePayment(event) {
  const amount = toInt(event.amount, NaN);
  if (!Number.isFinite(amount) || amount <= 0) throw new Error('Invalid amount');
  const currency = normalizeCurrency(event.currency);
  const method = String(event.method || '').trim() || 'card';
  const customerId = String(event.customerId || '').trim() || null;

  await new Promise((r) => setTimeout(r, 50));

  return {
    status: 'captured',
    paymentId: event.paymentId,
    amount,
    currency,
    method,
    customerId,
    processorRef: `proc_${Date.now()}_${Math.random().toString(16).slice(2)}`
  };
}

async function refundPayment(event) {
  const amount = event.amount == null ? null : toInt(event.amount, NaN);
  if (amount != null && (!Number.isFinite(amount) || amount <= 0)) throw new Error('Invalid refund amount');
  const currency = normalizeCurrency(event.currency);

  await new Promise((r) => setTimeout(r, 50));

  return {
    status: 'refunded',
    paymentId: event.paymentId,
    amount,
    currency,
    reason: String(event.reason || '').trim() || null
  };
}

async function voidPayment(event) {
  await new Promise((r) => setTimeout(r, 20));
  return { status: 'voided', paymentId: event.paymentId };
}

async function handlePaymentEvent(event) {
  switch (event.type) {
    case 'payment.charge':
      return await chargePayment(event);
    case 'payment.refund':
      return await refundPayment(event);
    case 'payment.void':
      return await voidPayment(event);
    default:
      throw new Error(`Unsupported event type: ${event.type}`);
  }
}

async function start() {
  const conn = await amqp.connect(RABBITMQ_URL);
  conn.on('error', (err) => {
    console.error('RabbitMQ connection error:', err);
    process.exitCode = 1;
  });
  conn.on('close', () => {
    console.error('RabbitMQ connection closed');
    process.exitCode = 1;
  });

  const ch = await conn.createChannel();
  await ch.assertQueue(QUEUE_NAME, { durable: true });
  await ch.prefetch(PREFETCH);

  console.log(`Consuming from queue: ${QUEUE_NAME} (prefetch=${PREFETCH})`);

  ch.consume(
    QUEUE_NAME,
    async (msg) => {
      if (!msg) return;
      const raw = msg.content;

      try {
        const event = validateEvent(parseJSON(raw));
        const result = await handlePaymentEvent(event);

        console.log(
          JSON.stringify(
            {
              ok: true,
              receivedAt: new Date().toISOString(),
              deliveryTag: msg.fields.deliveryTag,
              event,
              result
            },
            null,
            0
          )
        );

        ch.ack(msg);
      } catch (err) {
        console.error(
          JSON.stringify(
            {
              ok: false,
              receivedAt: new Date().toISOString(),
              deliveryTag: msg.fields.deliveryTag,
              error: { message: err && err.message ? err.message : String(err) },
              raw: raw && raw.toString ? raw.toString('utf8') : raw
            },
            null,
            0
          )
        );

        const requeue = false;
        ch.nack(msg, false, requeue);
      }
    },
    { noAck: false }
  );

  const shutdown = async () => {
    try {
      await ch.close();
    } catch {}
    try {
      await conn.close();
    } catch {}
    process.exit(0);
  };

  process.on('SIGINT', shutdown);
  process.on('SIGTERM', shutdown);
}

start().catch((err) => {
  console.error('Fatal error:', err);
  process.exit(1);
});